export const CARDS_LIFELINE_VOCAB = [
  { id: 751, category: "haikan", source: "vocab-lifeline", furi: "はいかん", jp: "配管", romaji: "haikan", id_text: "Perpipaan / pipa", desc: "Sistem pipa untuk mengalirkan fluida (air, gas, refrigeran, dll).", _origIndex: 742 },
  { id: 752, category: "haikan", source: "vocab-lifeline", furi: "まいせつ", jp: "埋設", romaji: "maisetsu", id_text: "Instalasi bawah tanah", desc: "Pemasangan pipa/kabel di bawah permukaan tanah. Di proyek: wajib catat posisi di gambar teknik. Mandor:「埋設管の位置を図面に記録して」(catat posisi pipa di gambar).", _origIndex: 743 },
  { id: 753, category: "haikan", source: "vocab-lifeline", furi: "ちか", jp: "地下", romaji: "chika", id_text: "Bawah tanah", desc: "Area di bawah permukaan tanah. 地下配管 = pipa bawah tanah. Di proyek: pastikan kedalaman sesuai standar. Mandor:「地下配管の深さを確認して」(cek kedalaman pipa bawah tanah).", _origIndex: 744 },
  { id: 757, category: "haikan", source: "vocab-lifeline", furi: "かんたん", jp: "管端", romaji: "kantan", id_text: "Ujung pipa", desc: "Bagian ujung pipa/selang. シーリング材を充填する = isi sealant di ujung pipa.", _origIndex: 747 },
  { id: 758, category: "haikan", source: "vocab-lifeline", furi: "がすはいかん", jp: "ガス配管", romaji: "gasu haikan", id_text: "Perpipaan gas", desc: "Sistem pipa untuk mengalirkan gas kota. Wajib uji kebocoran setelah sambungan.", _origIndex: 748 },
  { id: 759, category: "haikan", source: "vocab-lifeline", furi: "せつぞく", jp: "接続", romaji: "setsuzoku", id_text: "Penyambungan / koneksi", desc: "Menghubungkan dua bagian pipa atau kabel. Di proyek: setiap sambungan harus dicek kebocorannya. Mandor:「接続部の漏れを確認して」(cek kebocoran di titik sambungan).", _origIndex: 749 },
  { id: 760, category: "haikan", source: "vocab-lifeline", furi: "せつぞくぶ", jp: "接続部", romaji: "setsuzoku bu", id_text: "Bagian sambungan", desc: "Titik di mana dua pipa atau komponen bertemu. Di proyek: titik sambungan paling rentan bocor. Mandor:「接続部をしっかり締め付けて」(kencangkan bagian sambungan).", _origIndex: 750 },
  { id: 763, category: "haikan", source: "vocab-lifeline", furi: "かんかく", jp: "間隔", romaji: "kankaku", id_text: "Jarak / interval", desc: "Jarak antar saddle penyangga pipa. Jika terlalu jauh → lendutan (たわみ).", _origIndex: 751 },
  { id: 767, category: "hoon", source: "vocab-lifeline", furi: "ほおんざい", jp: "保温材", romaji: "hoonzai", id_text: "Material insulasi panas", desc: "Bahan yang membungkus pipa panas agar panas tidak hilang ke lingkungan.", _origIndex: 754 },
  { id: 768, category: "hoon", source: "vocab-lifeline", furi: "だんねつざい", jp: "断熱材", romaji: "dannetsu zai", id_text: "Material insulasi termal", desc: "Bahan pencegah perpindahan panas. Dipakai pada pipa panas & dingin.", _origIndex: 755 },
  { id: 770, category: "hoon", source: "vocab-lifeline", furi: "しーりんぐざい", jp: "シーリング材", romaji: "sheeringu zai", id_text: "Bahan sealant / penyegel", desc: "Material yang digunakan untuk menutup celah dan mencegah masuknya air/udara.", _origIndex: 756 },
  { id: 771, category: "hoon", source: "vocab-lifeline", furi: "ぜつえんてーぷ", jp: "絶縁テープ", romaji: "zetsunen teepu", id_text: "Selotip insulasi listrik", desc: "Pita perekat untuk mengisolasi kabel listrik. Berbeda fungsi dari sealant.", _origIndex: 757 },
  { id: 773, category: "hoon", source: "vocab-lifeline", furi: "たいこうせい", jp: "耐候性", romaji: "taikousei", id_text: "Ketahanan cuaca", desc: "Kemampuan material bertahan terhadap sinar UV, hujan, dan perubahan suhu di luar ruangan.", _origIndex: 759 },
  { id: 774, category: "hoon", source: "vocab-lifeline", furi: "あつさ", jp: "厚さ", romaji: "atsusa", id_text: "Ketebalan", desc: "Tebal material insulasi. Jika 断熱材 terlalu tipis → 結露 (kondensasi) sering terjadi.", _origIndex: 760 },
  { id: 810, category: "haikan", source: "vocab-lifeline", furi: "せんじょう", jp: "洗浄", romaji: "senjou", id_text: "Pembersihan", desc: "配管内面に錆が発生した場合 → 施工前に洗浄と防錆処理が必要. Di proyek: karat dalam pipa harus dibereskan sebelum mulai. Mandor:「施工前に配管内を洗浄して防錆処理をして」(cuci dan anti-karat sebelum pasang).", _origIndex: 795 },
  { id: 815, category: "denki", source: "vocab-lifeline", furi: "でんきせつび", jp: "電気設備", romaji: "denki setsubi", id_text: "Peralatan listrik", desc: "Sistem & peralatan yang berhubungan dengan listrik. アース取付が義務.", _origIndex: 799 },
  { id: 816, category: "denki", source: "vocab-lifeline", furi: "でんどうこうぐ", jp: "電動工具", romaji: "dendou kougu", id_text: "Alat listrik (power tool)", desc: "Alat kerja yang ditenagai listrik. Jika kabel panas saat dipakai → segera 使用中止.", _origIndex: 800 },
  { id: 817, category: "denki", source: "vocab-lifeline", furi: "でんげん", jp: "電源", romaji: "dengen", id_text: "Sumber daya / power supply", desc: "Sumber listrik untuk peralatan. 電源を強くする = memperkuat daya (bukan solusi jika kabel panas).", _origIndex: 801 },
  { id: 819, category: "denki", source: "vocab-lifeline", furi: "ふくすう", jp: "複数", romaji: "fukusuu", id_text: "Beberapa / jamak", desc: "複数の電線を束ねて配管に通す場合 = saat memasukkan beberapa kabel dalam satu konduit.", _origIndex: 803 },
  { id: 833, category: "hoon", source: "vocab-lifeline", furi: "ざいりょう", jp: "材料", romaji: "zairyou", id_text: "Material / bahan", desc: "Bahan yang digunakan dalam konstruksi. 材料の色 sering muncul sebagai pengecoh di soal ujian.", _origIndex: 817 },
  { id: 834, category: "denki", source: "vocab-lifeline", furi: "こーど", jp: "コード", romaji: "koodo", id_text: "Kabel / kord (power tool)", desc: "Kabel listrik pada 電動工具. コードが熱くなる = kabel terasa panas → tanda bahaya → 使用中止.", _origIndex: 818 },
  { id: 843, category: "denki", source: "vocab-lifeline", furi: "でんせん", jp: "電線", romaji: "densen", id_text: "Kabel listrik / kawat", desc: "Kawat penghantar listrik. Berbeda dari 電線管（konduit pelindung）. 電線を複数束ねて通す = memasukkan banyak kabel sekaligus → panas terperangkap.", _origIndex: 827 },
  { id: 851, category: "haikan", source: "vocab-lifeline", furi: "ながれ", jp: "流れ", romaji: "nagare", id_text: "Aliran (fluida)", desc: "流れが悪くなる = aliran memburuk. Terjadi akibat 勾配不足（kemiringan pipa tidak cukup）→ fluida tidak mengalir lancar → bisa menggenang.", _origIndex: 835 },
  { id: 873, category: "haikan", source: "vocab-lifeline", furi: "ひろい", jp: "広い", romaji: "hiroi", id_text: "Lebar / luas", desc: "サドル間隔が広すぎる = jarak saddle terlalu lebar. Konteks Q17 — penyebab たわみが発生する (lendutan terjadi). Interval saddle harus sesuai spesifikasi pipa.", _origIndex: 857 },
  { id: 889, category: "haikan", source: "vocab-lifeline", furi: "とおす", jp: "通す", romaji: "toosu", id_text: "Melewatkan / meneruskan", desc: "配管に通す = melewatkan melalui konduit/pipa. Konteks Q18: 電線を配管に通す場合の注意点 = hal yang diperhatikan saat kabel dimasukkan ke konduit.", _origIndex: 873 },
  { id: 890, category: "haikan", source: "vocab-lifeline", furi: "ひらく", jp: "開く", romaji: "hiraku", id_text: "Membuka", desc: "バルブを開いた直後 = segera setelah katup dibuka. Konteks Q19: membuka katup terlalu cepat → 流量が急変 → 異音が発生する. バルブはゆっくり開くべき.", _origIndex: 874 },
  { id: 896, category: "haikan", source: "vocab-lifeline", furi: "うめる", jp: "埋める", romaji: "umeru", id_text: "Mengubur / menanam (pipa)", desc: "配管を埋める = mengubur pipa (di bawah tanah). Muncul sebagai opsi Q1: 浅く埋める (kubur dangkal — pengecoh), 裸のまま埋める (kubur tanpa pelindung — pengecoh). Yang benar: 保温材＋電熱線を併用して埋める.", _origIndex: 880 },
  { id: 908, category: "hoon", source: "vocab-lifeline", furi: "こうじ", jp: "工事", romaji: "kouji", id_text: "Pekerjaan konstruksi", desc: "保冷工事（Q4）= pekerjaan insulasi dingin. 工事 = pekerjaan konstruksi secara umum (berskala proyek). Lebih besar dari 作業（さぎょう）= operasi kerja harian. 工事中 = sedang dalam konstruksi.", _origIndex: 892 },
  { id: 933, category: "haikan", source: "vocab-jac", furi: "うめもどし", jp: "埋戻し", romaji: "umemodoshi", id_text: "Urugan kembali / backfill", desc: "例: 配管設置後に埋戻しを行う。→ Setelah pipa terpasang, uruk kembali tanah di atasnya.", _origIndex: 917 },
  { id: 947, category: "haikan", source: "vocab-jac", furi: "しほこう", jp: "支保工", romaji: "shihokou", id_text: "Perancah penyangga / shoring", desc: "例: 型枠を鉄パイプで支保工する。→ Perkuat bekisting menggunakan perancah dari pipa baja.", _origIndex: 931 },
  { id: 956, category: "haikan", source: "vocab-jac", furi: "かんろ", jp: "管路", romaji: "kanro", id_text: "Jalur pipa / conduit path", desc: "例: マンホール間を結ぶのが管路。→ Jalur pipa yang menghubungkan antar manhole.", _origIndex: 940 },
  { id: 957, category: "haikan", source: "vocab-jac", furi: "まいせつぶつ", jp: "埋設物", romaji: "maisetsu butsu", id_text: "Utilitas bawah tanah / buried utilities", desc: "例: 穴を掘る前に埋設物を確認する。→ Sebelum menggali, periksa dulu ada tidaknya pipa/kabel bawah tanah.", _origIndex: 941 },
  { id: 958, category: "haikan", source: "vocab-jac", furi: "たてこう", jp: "立坑", romaji: "tatekou", id_text: "Shaft vertikal / sumur akses", desc: "例: 推進工事の発進立坑をジャッキで掘る。→ Shaft vertikal dipakai sebagai titik start konstruksi jacking.", _origIndex: 942 },
  { id: 959, category: "haikan", source: "vocab-jac", furi: "きょうどうこう", jp: "共同溝", romaji: "kyoudoukou", id_text: "Saluran utilitas bersama", desc: "例: 電気・ガス・水道を共同溝にまとめる。→ Listrik, gas, air bersih dikumpulkan dalam 1 saluran bawah tanah.", _origIndex: 943 },
  { id: 962, category: "denki", source: "vocab-jac", furi: "ぜつえん", jp: "絶縁", romaji: "zetsuen", id_text: "Insulasi listrik", desc: "例: 電気が他の部分に流れないよう絶縁する。→ Cegah arus mengalir ke bagian lain dengan insulasi.", _origIndex: 946 },
  { id: 963, category: "denki", source: "vocab-jac", furi: "せっち", jp: "接地", romaji: "secchi", id_text: "Pentanahan / grounding", desc: "例: 感電防止のため電気設備にアース(接地)を取る。→ Pasang grounding di peralatan listrik untuk cegah sengatan.", _origIndex: 947 },
  { id: 964, category: "denki", source: "vocab-jac", furi: "ろうでん", jp: "漏電", romaji: "rouden", id_text: "Kebocoran listrik", desc: "例: 漏電は感電・火災の原因になる。→ Kebocoran listrik bisa menyebabkan sengatan dan kebakaran.", _origIndex: 948 },
  { id: 965, category: "denki", source: "vocab-jac", furi: "たんらく", jp: "短絡", romaji: "tanraku", id_text: "Korsleting / short circuit", desc: "例: 2本以上の電線が負荷なしに接触すると短絡。→ Dua kabel bersentuhan tanpa beban = korsleting.", _origIndex: 949 },
  { id: 988, category: "haikan", source: "vocab-core", furi: "せつごう", jp: "接合", romaji: "setsugou", id_text: "Penyambungan / joint", desc: "例: 鉄管はねじ接合、ポリエチレン管はEF接合。→ Pipa baja = sambungan ulir; pipa PE = sambungan EF.", _origIndex: 972 },
  { id: 989, category: "denki", source: "vocab-core", furi: "でんちゅう", jp: "電柱", romaji: "denchuu", id_text: "Tiang listrik / utility pole", desc: "例: 電柱を建てる前に埋設物を確認する。→ Sebelum pasang tiang listrik, cek utilitas bawah tanah.", _origIndex: 973 },
  { id: 990, category: "denki", source: "vocab-core", furi: "まんほーる", jp: "マンホール", romaji: "manhoooru", id_text: "Manhole", desc: "例: マンホール内は酸素欠乏と有害ガスに注意。→ Di dalam manhole, waspadai kekurangan oksigen dan gas berbahaya.", _origIndex: 974 },
  { id: 1007, category: "haikan", source: "vocab-lifeline", furi: "きゅうとうかん", jp: "給湯管", romaji: "kyuutou kan", id_text: "Pipa air panas (suplai)", desc: "Pipa yang menyalurkan air panas ke keran, shower, dll. Berbeda dari 温水管 (lebih umum).", _origIndex: 986 },
  { id: 1012, category: "haikan", source: "vocab-lifeline", furi: "ぱいぷれんち", jp: "パイプレンチ", romaji: "paipu renchi", id_text: "Kunci pipa (pipe wrench)", desc: "Kunci khusus bergigi untuk memutar dan mengencangkan pipa besi/baja.", _origIndex: 991 },
  { id: 1020, category: "denki", source: "vocab-lifeline", furi: "ちちゅうけーぶる", jp: "地中ケーブル", romaji: "chichuu keeburu", id_text: "Kabel bawah tanah", desc: "Kabel listrik yang ditanam di bawah tanah, biasanya dalam konduit pelindung.", _origIndex: 999 },
  { id: 1021, category: "denki", source: "vocab-lifeline", furi: "ちじょうけーぶる", jp: "地上ケーブル", romaji: "chijou keeburu", id_text: "Kabel di atas tanah", desc: "Kabel listrik yang dipasang di permukaan tanah atau di atas permukaan.", _origIndex: 1000 },
  { id: 1022, category: "denki", source: "vocab-lifeline", furi: "かくうけーぶる", jp: "架空ケーブル", romaji: "kakuu keeburu", id_text: "Kabel udara / overhead cable", desc: "Kabel listrik yang dibentangkan di atas tiang (電柱). Paling umum di jalanan Jepang.", _origIndex: 1001 },
  { id: 1028, category: "haikan", source: "vocab-lifeline", furi: "かつざいのとふ", jp: "滑剤の塗布", romaji: "katsuzai no tofu", id_text: "Pengolesan pelumas", desc: "Melumasi bagian sambungan pipa agar mudah dimasukkan. Langkah penting dalam pemasangan pipa ductile.", _origIndex: 1007 },
  { id: 1030, category: "haikan", source: "vocab-lifeline", furi: "ごむわのせっと", jp: "ゴム輪のセット", romaji: "gomu wa no setto", id_text: "Pemasangan cincin karet", desc: "Memasang o-ring/gasket karet pada alur pipa sebelum penyambungan. Fungsi: mencegah kebocoran.", _origIndex: 1009 },
  { id: 1031, category: "haikan", source: "vocab-lifeline", furi: "ごむわのいち", jp: "ゴム輪の位置", romaji: "gomu wa no ichi", id_text: "Posisi cincin karet", desc: "Memastikan cincin karet berada pada posisi yang benar di alur pipa. Posisi salah = kebocoran.", _origIndex: 1010 },
  { id: 1032, category: "haikan", source: "vocab-lifeline", furi: "ゆうちゃくじゅんび", jp: "融着準備", romaji: "yuuchaku junbi", id_text: "Persiapan fusi (EF welding)", desc: "Langkah-langkah persiapan sebelum proses electrofusion welding pada pipa polietilen.", _origIndex: 1011 },
  { id: 1034, category: "haikan", source: "vocab-lifeline", furi: "いーえふそけっと", jp: "EFソケット", romaji: "EF soketto", id_text: "Soket EF (electrofusion socket)", desc: "Fitting elektrofusi yang memiliki kawat pemanas internal. Digunakan untuk menyambung pipa polietilen.", _origIndex: 1013 },
  { id: 1035, category: "denki", source: "vocab-lifeline", furi: "こんとろーら", jp: "コントローラ", romaji: "kontroora", id_text: "Pengontrol (controller)", desc: "Alat pengontrol yang mengatur proses fusi, suhu, atau operasi mesin.", _origIndex: 1014 },
  { id: 1036, category: "denki", source: "vocab-lifeline", furi: "いんじけーた", jp: "インジケータ", romaji: "injikeeta", id_text: "Indikator", desc: "Alat penunjuk status atau kondisi. Contoh: indikator tekanan, suhu, atau daya.", _origIndex: 1015 },
  { id: 1041, category: "haikan", source: "vocab-lifeline", furi: "だくとのせつぞくほうほう", jp: "ダクト接続方法", romaji: "dakuto no setsuzoku houhou", id_text: "Metode sambungan duct/saluran", desc: "Cara-cara menyambung saluran udara (ducting). Termasuk metode flange dan metode tanpa flange.", _origIndex: 1020 },
  { id: 1042, category: "haikan", source: "vocab-lifeline", furi: "あんぐるふらんじ", jp: "アングルフランジ", romaji: "anguru furanji", id_text: "Flensa bersudut (angle flange)", desc: "Tipe flange dari besi siku yang dipasang di tepi duct untuk penyambungan dengan baut.", _origIndex: 1021 },
  { id: 1047, category: "denki", source: "vocab-lifeline", furi: "こうあつ・ていあつ", jp: "高圧・低圧", romaji: "kouatsu / teiatsu", id_text: "Tegangan tinggi dan rendah", desc: "Klasifikasi tegangan listrik. 高圧: di atas 600V. 低圧: 600V ke bawah. Penting untuk keselamatan.", _origIndex: 1026 },
  { id: 1053, category: "haikan", source: "vocab-lifeline", furi: "きゃっぷ", jp: "キャップ", romaji: "kyappu", id_text: "Cap / penutup ujung pipa", desc: "Tutup yang dipasang di ujung pipa untuk menutup aliran. Di proyek: dipasang saat pengujian tekanan. Mandor:「テスト前にキャップを取り付けて」(pasang cap sebelum uji tekanan).", _origIndex: 1032 },
  { id: 1054, category: "haikan", source: "vocab-lifeline", furi: "こっく", jp: "コック", romaji: "kokku", id_text: "Keran kecil / cock valve", desc: "Katup kecil untuk mengatur aliran, lebih kecil dari バルブ. Di proyek: buka perlahan untuk hindari water hammer. Mandor:「コックはゆっくり開いて」(buka keran perlahan-lahan).", _origIndex: 1033 },
  { id: 1057, category: "haikan", source: "vocab-lifeline", furi: "しんえんしゅうせい", jp: "真円修正", romaji: "shin'en shuusei", id_text: "Koreksi kebulatan pipa", desc: "Proses mengembalikan bentuk pipa yang oval/penyok menjadi bulat sempurna.", _origIndex: 1036 },
  { id: 1058, category: "haikan", source: "vocab-lifeline", furi: "かんかこう", jp: "管加工", romaji: "kan kakou", id_text: "Pengolahan/pemrosesan pipa", desc: "Semua proses pengerjaan pipa: potong, tekuk, chamfer, deburring, dll.", _origIndex: 1037 },
  { id: 1072, category: "denki", source: "vocab-lifeline", furi: "ほごテープ", jp: "保護テープ", romaji: "hogo teepu", id_text: "Pita pelindung (protective tape)", desc: "Pita untuk melindungi kabel/pipa dari gesekan atau kerusakan fisik. Berbeda dari 絶縁テープ.", _origIndex: 1051 },
  { id: 1073, category: "denki", source: "vocab-lifeline", furi: "けっそくバンド", jp: "結束バンド", romaji: "kessoku bando", id_text: "Cable tie / pengikat kabel", desc: "Tali plastik untuk mengikat dan merapikan kumpulan kabel listrik.", _origIndex: 1052 },
  { id: 1081, category: "haikan", source: "vocab-lifeline", furi: "はいすいポンプ", jp: "排水ポンプ", romaji: "haisui ponpu", id_text: "Pompa air limbah (drainage pump)", desc: "Pompa untuk mengalirkan air limbah/kotor dari gedung ke saluran pembuangan.", _origIndex: 1060 },
  { id: 1082, category: "haikan", source: "vocab-lifeline", furi: "れいきゃくポンプ", jp: "冷却ポンプ", romaji: "reikyaku ponpu", id_text: "Pompa pendingin (cooling pump)", desc: "Pompa untuk mengalirkan air pendingin di sistem AC sentral atau chiller. Di proyek: perlu dicek putaran dan tekanannya. Mandor:「冷却ポンプの圧力を確認して」(cek tekanan pompa pendingin).", _origIndex: 1061 },
  { id: 1086, category: "haikan", source: "vocab-lifeline", furi: "きゅうすいたんく", jp: "給水タンク", romaji: "kyuusui tanku", id_text: "Tangki air bersih (water supply tank)", desc: "Tangki penampung air bersih di gedung, biasanya di atap atau ruang bawah tanah.", _origIndex: 1065 },
  { id: 1095, category: "tsushin", source: "vocab-lifeline", furi: "ひかりケーブルちちゅうはいせん", jp: "光ケーブル地中配線", romaji: "hikari keepuru chichuu haisen", id_text: "Pengabelan kabel optik bawah tanah", desc: "Pemasangan kabel serat optik di dalam tanah melalui 管路 atau 共同溝.", _origIndex: 1074 },
  { id: 1096, category: "haikan", source: "vocab-lifeline", furi: "かしつき", jp: "加湿器", romaji: "kashitsuki", id_text: "Humidifier / pelembab udara", desc: "Alat untuk menambah kelembaban udara ruangan. Bagian dari sistem HVAC.", _origIndex: 1075 },
  { id: 1097, category: "shoubou", source: "vocab-exam", furi: "すぷりんくらーへっど", jp: "スプリンクラーヘッド", romaji: "supurinkuraa heddo", id_text: "Kepala sprinkler pemadam api", desc: "例: スプリンクラーヘッドは火災時に熱で溶栓が溶けて自動放水する。→ Kepala sprinkler meleleh saat suhu tinggi dan memancarkan air secara otomatis. Ada dua jenis: 開放型 (terbuka) dan 閉鎖型 (tertutup).", _origIndex: 1076 },
  { id: 1098, category: "shoubou", source: "vocab-exam", furi: "かいほうがたすぷりんくらー", jp: "開放型スプリンクラー", romaji: "kaihou gata supurinkuraa", id_text: "Sprinkler jenis terbuka (open)", desc: "例: 開放型スプリンクラーは舞台や劇場など広い空間に使われる。→ Sprinkler terbuka digunakan di panggung atau ruang besar; semua kepala menyembur serentak saat katup utama dibuka.", _origIndex: 1077 },
  { id: 1099, category: "shoubou", source: "vocab-exam", furi: "へいさがたすぷりんくらー", jp: "閉鎖型スプリンクラー", romaji: "heisa gata supurinkuraa", id_text: "Sprinkler jenis tertutup (closed)", desc: "例: 閉鎖型スプリンクラーは感熱部が溶けた箇所だけ放水する。→ Sprinkler tertutup hanya menyembur di kepala yang terkena panas; paling umum digunakan di gedung bertingkat.", _origIndex: 1078 },
  { id: 1106, category: "shoubou", source: "vocab-exam", furi: "ひなんはしご", jp: "避難はしご", romaji: "hinan hashigo", id_text: "Tangga evakuasi darurat", desc: "例: 避難はしごは窓に取り付けて外壁を伝って降りる避難器具だ。→ Tangga evakuasi dipasang di jendela untuk turun menyusuri dinding luar gedung saat lift tidak bisa digunakan.", _origIndex: 1085 },
  { id: 1109, category: "shoubou", source: "vocab-exam", furi: "ぼうかだんぱー", jp: "防火ダンパー", romaji: "bouka danpaa", id_text: "Fire damper (katup pemadam di ducting)", desc: "例: 防火ダンパーはダクトが防火区画を貫通する部分に設置する。→ Dipasang di titik duct yang menembus dinding tahan api; menutup otomatis saat sensor meleleh akibat panas untuk mencegah api merambat lewat ducting.", _origIndex: 1088 },
  { id: 1112, category: "shoubou", source: "vocab-exam", furi: "しょうかぽんぷ", jp: "消火ポンプ", romaji: "shouka ponpu", id_text: "Pompa pemadam kebakaran", desc: "例: 消火ポンプは加圧送水装置として屋内消火栓やスプリンクラーに水を供給する。→ Pompa pemadam menyuplai air bertekanan ke sistem hidran dan sprinkler; dilengkapi 性能試験装置 untuk pengujian berkala.", _origIndex: 1091 },
  { id: 1115, category: "shoubou", source: "vocab-exam", furi: "はっしんき", jp: "発信機", romaji: "hasshin ki", id_text: "Tombol alarm kebakaran manual", desc: "例: 発信機は人が火災を発見した際に手動で押して警報を鳴らす装置だ。→ Manual call point; ditekan oleh orang yang melihat api untuk mengaktifkan alarm; biasanya berwarna merah dan dipasang di koridor tiap lantai.", _origIndex: 1094 },
  { id: 1116, category: "shoubou", source: "vocab-exam", furi: "じゅしんき", jp: "受信機", romaji: "jushin ki", id_text: "Panel penerima alarm kebakaran", desc: "例: 受信機は感知器や発信機からの信号を受けて警報を表示・発報する中枢装置だ。→ Panel utama sistem alarm kebakaran yang menampilkan lokasi kebakaran dan mengaktifkan bel; biasanya di ruang penjaga gedung.", _origIndex: 1095 },
  { id: 1119, category: "shoubou", source: "vocab-exam", furi: "しょうぼうようすい", jp: "消防用水", romaji: "shoubouyousui", id_text: "Cadangan air untuk pemadam kebakaran", desc: "例: 消防用水は敷地内に一定量の水を貯留しておく消防設備の一種だ。→ Tangki atau kolam cadangan air yang wajib tersedia di lokasi tertentu; digunakan sebagai sumber air alternatif saat pasokan PDAM tidak cukup.", _origIndex: 1098 },
  { id: 1122, category: "hoon", source: "vocab-exam", furi: "ろっくうーる", jp: "ロックウール", romaji: "rokku uuru", id_text: "Rock wool / wol batu", desc: "例: ロックウールはグラスウールより耐熱温度が高く、約600℃まで使用できる。→ Rock wool tahan panas lebih tinggi dari glass wool, bisa digunakan hingga ±600°C. Terbuat dari basalt/batu terak, lebih berat tapi lebih tahan api.", _origIndex: 1101 },
  { id: 1125, category: "hoon", source: "vocab-exam", furi: "こうしつうれたんふぉーむ", jp: "硬質ウレタンフォーム", romaji: "koushitsu uretan foomu", id_text: "Rigid urethane foam (board/panel)", desc: "例: 硬質ウレタンフォームボードは熱伝導率が非常に低く、薄くても高い断熱性能を発揮する。→ Papan busa uretan keras memiliki nilai λ sangat rendah (~0.022 W/mK), efisien untuk ruang sempit. Beda dengan吹付けウレタン yang disemprotkan di tempat.", _origIndex: 1104 },
  { id: 1127, category: "hoon", source: "vocab-exam", furi: "ぱーらいとほおんざい", jp: "パーライト保温材", romaji: "paaraito hoon zai", id_text: "Perlite insulation material", desc: "例: パーライト保温材は膨張させた真珠岩を原料とし、高温配管や機器の保温に使われる。→ Insulasi perlit terbuat dari obsidian/batu vulkanik yang dipanaskan hingga mengembang.", _origIndex: 1106 },
  { id: 1128, category: "hoon", source: "vocab-exam", furi: "がいそうざい", jp: "外装材", romaji: "gaisou zai", id_text: "Jacketing material / material pelapis luar", desc: "例: 保温材の外装材には、アルミ・亜鉛鉄板・ステンレスなどが使われる。→ Material penutup luar lapisan insulasi pipa/duct untuk melindungi dari cuaca dan benturan fisik.", _origIndex: 1107 },
  { id: 1129, category: "hoon", source: "vocab-exam", furi: "あるみがいそう", jp: "アルミ外装", romaji: "arumi gaisou", id_text: "Aluminum jacketing (outer cladding)", desc: "例: 屋外露出配管の保温仕上げには、軽量で耐候性のあるアルミ外装が多く採用される。→ Jacketing aluminium ringan dan tahan karat, umum dipakai pada pipa outdoor.", _origIndex: 1108 },
  { id: 1133, category: "hoon", source: "vocab-exam", furi: "ほおんとう", jp: "保温筒", romaji: "hoontou", id_text: "Pre-formed pipe insulation section", desc: "例: 保温筒は配管の外径に合わせて半円形に成形された保温材で、2枚合わせて取り付ける。→ Insulasi pipa berbentuk silinder yang sudah dicetak setengah lingkaran, dipasang memeluk pipa.", _origIndex: 1112 },
  { id: 1134, category: "hoon", source: "vocab-exam", furi: "ほおんたい", jp: "保温帯", romaji: "hoontai", id_text: "Insulation band / blanket strip", desc: "例: バルブやフランジなど複雑な形状の箇所には保温筒の代わりに保温帯を巻き付けて施工する。→ Strip insulasi fleksibel (blanket) yang dililitkan pada bagian pipa tidak beraturan seperti valve, fitting, dan flensa yang tidak bisa memakai 保温筒", _origIndex: 1113 },
  { id: 1146, category: "hoon", source: "vocab-exam", furi: "ほれいこうじ", jp: "保冷工事", romaji: "horei kouji", id_text: "Cold insulation work / refrigeration insulation", desc: "例: 保冷工事では、外部からの熱侵入を防ぐとともに、結露による腐食も防止しなければならない。→ Pekerjaan insulasi khusus untuk pipa/peralatan bersuhu rendah (pipa chiller, AC, freezer).", _origIndex: 1125 },
  { id: 1147, category: "denki", source: "vocab-exam", furi: "ぶんでんばん", jp: "分電盤", romaji: "bunden ban", id_text: "Panel distribusi / breaker box", desc: "例: 分電盤には主幹ブレーカーと複数の分岐ブレーカーが設置されている。→ Panel distribusi berisi breaker utama dan breaker-breaker cabang untuk tiap sirkuit.", _origIndex: 1126 },
  { id: 1155, category: "denki", source: "vocab-exam", furi: "たんそう", jp: "単相", romaji: "tansou", id_text: "Fase tunggal / single phase", desc: "例: 家庭用電源は単相2線式（100V）または単相3線式（100V/200V）が標準である。→ Listrik rumah tangga umumnya menggunakan single phase 2 kawat (100V) atau 3 kawat (100V/200V).", _origIndex: 1134 },
  { id: 1157, category: "denki", source: "vocab-exam", furi: "きょようでんりゅう", jp: "許容電流", romaji: "kyoyou denryuu", id_text: "Ampasitas / arus maksimum yang diizinkan", desc: "例: 電線の許容電流を超えると絶縁被覆が過熱し、火災の原因となる。→ Jika arus melebihi ampasitas kabel, isolasi akan kepanasan dan dapat menyebabkan kebakaran.", _origIndex: 1136 },
  { id: 1162, category: "denki", source: "vocab-exam", furi: "ていあつ", jp: "低圧", romaji: "teiatsu", id_text: "Tegangan rendah (AC ≤600V / DC ≤750V)", desc: "例: 電気設備技術基準では交流600V以下・直流750V以下を低圧と定義している。→ Standar teknis instalasi listrik mendefinisikan tegangan rendah sebagai AC ≤600V atau DC ≤750V.", _origIndex: 1141 },
  { id: 1163, category: "denki", source: "vocab-exam", furi: "こうあつ", jp: "高圧", romaji: "kouatsu", id_text: "Tegangan tinggi (AC 600V–7000V)", desc: "例: 交流600Vを超え7000V以下の電圧を高圧といい、工場やビルの受電設備に使われる。→ Tegangan AC di atas 600V hingga 7000V disebut tegangan tinggi, digunakan di panel penerimaan pabrik dan gedung.", _origIndex: 1142 },
  { id: 1166, category: "denki", source: "vocab-exam", furi: "せいぎょけーぶる", jp: "制御ケーブル", romaji: "seigyo keeburu", id_text: "Kabel kontrol / sinyal", desc: "例: 制御ケーブルは動力ケーブルと分離して配線し、電磁ノイズによる誤作動を防ぐ。→ Kabel kontrol harus dipisah dari kabel daya untuk mencegah gangguan sinyal akibat interferensi elektromagnetik.", _origIndex: 1144 },
  { id: 1171, category: "denki", source: "vocab-exam", furi: "でんきこうじし", jp: "電気工事士", romaji: "denki kouji shi", id_text: "Teknisi listrik berlisensi — tingkat 1 dan 2", desc: "例: 第二種電気工事士は一般用電気工作物（交流600V以下）の電気工事を行える国家資格である。→ Lisensi teknisi listrik tingkat 2 memungkinkan pengerjaan instalasi listrik tegangan rendah (AC ≤600V).", _origIndex: 1149 },
  { id: 1178, category: "haikan", source: "vocab-exam", furi: "フランジせつごう", jp: "フランジ接合", romaji: "furangi setsugou", id_text: "Sambungan flange / flange joint", desc: "例: フランジ接合はボルト・ナットで締め付け、ガスケットで気密を保つ。→ Sambungan flange diikat baut-mur dan disekat gasket; mudah dibongkar pasang untuk perawatan.", _origIndex: 1156 },
  { id: 1179, category: "haikan", source: "vocab-exam", furi: "ソケットせつごう", jp: "ソケット接合", romaji: "soketto setsugou", id_text: "Sambungan soket / socket joint", desc: "例: 塩ビ管のソケット接合では、接着剤を均一に塗布してから素早く挿入する。→ Pada sambungan soket pipa PVC, oleskan lem merata lalu masukkan pipa dengan cepat sebelum lem mengering.", _origIndex: 1157 },
  { id: 1180, category: "haikan", source: "vocab-exam", furi: "グルーブドせつごう", jp: "グルーブド接合", romaji: "guruubudo setsugou", id_text: "Sambungan grooved / Victaulic joint", desc: "例: グルーブド接合はパイプ端に溝を加工し、カップリングとガスケットで接合するため、工期が短い。→ Sambungan grooved menggunakan alur di ujung pipa dan coupling; pengerjaan lebih cepat dibanding las.", _origIndex: 1158 },
  { id: 1189, category: "haikan", source: "vocab-exam", furi: "よびけい", jp: "呼び径", romaji: "yobi kei", id_text: "Nominal diameter / ukuran nominal pipa", desc: "例: 呼び径25Aの鋼管は外径34mm、実際の内径は25mmより若干異なる。→ Pipa baja 25A berarti ukuran nominal 25 mm; diameter sebenarnya sedikit berbeda tergantung standar A atau B.", _origIndex: 1167 },
  { id: 1190, category: "haikan", source: "vocab-exam", furi: "きみつしけん", jp: "気密試験", romaji: "kimitsu shiken", id_text: "Air tightness test / uji kebocoran udara", desc: "例: ガス配管の気密試験では、設定圧力で所定時間保持し、圧力降下がないか確認する。→ Pada pipa gas, lakukan uji tekanan udara pada tekanan yang ditentukan dan pantau apakah ada penurunan tekanan.", _origIndex: 1168 },
  { id: 1191, category: "haikan", source: "vocab-exam", furi: "きゅうすいかん", jp: "給水管", romaji: "kyuusui kan", id_text: "Pipa suplai air bersih", desc: "例: 給水管は水道本管から分岐し、各器具へ水を供給する。→ Pipa suplai air bersih bercabang dari jaringan utama PDAM dan mendistribusikan air ke setiap fixture bangunan.", _origIndex: 1169 },
  { id: 1192, category: "haikan", source: "vocab-exam", furi: "はいすいかん", jp: "排水管", romaji: "haisui kan", id_text: "Pipa drainase / buangan air limbah", desc: "例: 排水管は適切な勾配（一般的に1/100）を確保して詰まりを防ぐ。→ Pipa drainase harus dipasang dengan kemiringan memadai (umumnya 1/100) agar aliran lancar dan tidak mampet.", _origIndex: 1170 },
  { id: 1193, category: "haikan", source: "vocab-exam", furi: "ニップル", jp: "ニップル", romaji: "nippuru", id_text: "Nipple / sambungan pendek berulir dua sisi", desc: "例: ニップルは両端に雄ねじが切ってあり、ソケットや機器との短距離接続に使う。→ Nipple memiliki ulir jantan di kedua ujungnya; dipakai untuk menyambung dua fitting yang berdekatan.", _origIndex: 1171 },
  { id: 1201, category: "tsushin", source: "vocab-exam", furi: "えすしーこねくた", jp: "SCコネクタ", romaji: "esu shii konekuta", id_text: "Konektor fiber optik tipe SC (push-pull)", desc: "例: SCコネクタはプッシュプル式でワンタッチ着脱でき、ONU接続によく使われる。→ Konektor SC bertipe push-pull, mudah dipasang dan dilepas, sering dipakai pada sambungan ONU.", _origIndex: 1179 },
  { id: 1202, category: "tsushin", source: "vocab-exam", furi: "えるしーこねくた", jp: "LCコネクタ", romaji: "eru shii konekuta", id_text: "Konektor fiber optik tipe LC, lebih kecil dari SC", desc: "例: LCコネクタはSCより小型で高密度実装が可能なため、データセンターのスイッチに多用される。→ LC lebih kecil dari SC dan memungkinkan kepadatan tinggi, banyak dipakai di switch data center.", _origIndex: 1180 },
  { id: 1209, category: "tsushin", source: "vocab-exam", furi: "つうしんらっく", jp: "通信ラック", romaji: "tsuushin rakku", id_text: "Rak perangkat telekomunikasi standar 19 inci", desc: "例: 通信ラックは19インチ規格が主流で、スイッチ・パッチパネル・サーバーを搭載できる。→ Rak telekomunikasi umumnya berstandar 19 inci, mampu menampung switch, patch panel, dan server.", _origIndex: 1187 },
  { id: 1210, category: "tsushin", source: "vocab-exam", furi: "つうしんきゃびねっと", jp: "通信キャビネット", romaji: "tsuushin kyabinetto", id_text: "Kabinet tertutup untuk perangkat telekomunikasi", desc: "例: 屋外設置の通信キャビネットは防水・防塵（IP55以上）構造が必要だ。→ Kabinet telekomunikasi untuk pemasangan luar ruangan harus memiliki konstruksi tahan air dan debu (IP55 ke atas).", _origIndex: 1188 },
  { id: 1213, category: "tsushin", source: "vocab-exam", furi: "ほあんき", jp: "保安器", romaji: "hoaan ki", id_text: "Pelindung jalur masuk telepon (arrester/protector)", desc: "例: 保安器は雷サージや過電流から屋内の通信機器を保護するために引き込み口に設置される。→ Hoaan-ki dipasang di titik masuk kabel untuk melindungi peralatan komunikasi dalam gedung dari lonjakan petir dan arus lebih.", _origIndex: 1191 },
  { id: 1275, category: "setsubi_kougu", source: "vocab-exam", furi: "システムてんじょう", jp: "システム天井", romaji: "shisutemu tenjoo", id_text: "Plafon sistem / suspended ceiling modular", desc: "例: オフィスビルのシステム天井は照明・空調・防災設備を一体で収める。→ Plafon sistem pada gedung perkantoran mengintegrasikan pencahayaan, AC, dan peralatan kebakaran dalam satu modul yang dapat dibongkar-pasang untuk perawatan.", _origIndex: 1253 },
  { id: 1321, category: "haikan", source: "vocab-exam", furi: "しんくうぽんぷ", jp: "真空ポンプ", romaji: "shinkuu ponpu", id_text: "Pompa vakum / vacuum pump", desc: "例: 真空ポンプは冷媒配管の施工後、真空引きして水分・空気を除去するために使う。→ Pompa vakum digunakan setelah pemasangan pipa refrigerant (冷媒管) untuk mengosongkan udara dan kelembaban melalui proses vakumisasi (真空引き)", _origIndex: 1299 },
  { id: 1370, category: "haikan", source: "vocab-teori", furi: "れいばい", jp: "冷媒", romaji: "reibai", id_text: "Refrigeran / zat pendingin AC (HFC dll)", desc: "例: エアコンの冷媒管には冷媒が封入されており、接続時には漏れ試験が必須だ。→ Pipa refrigeran AC berisi zat pendingin; sambungan wajib diuji kebocoran setelah pemasangan. 冷媒管の接続後は必ず漏れ確認.", _origIndex: 1342 },
  { id: 1371, category: "haikan", source: "vocab-teori", furi: "こうばい", jp: "勾配", romaji: "koubai", id_text: "Kemiringan pipa drainase agar aliran lancar", desc: "例: 排水管は水が自然に流れるよう、必ず適切な勾配をつけて配管する。→ Pipa drainase harus dipasang dengan kemiringan yang cukup agar air mengalir secara gravitasi. 勾配不足 → 水が溜まり、流れが悪くなる.", _origIndex: 1343 },
  { id: 1372, category: "haikan", source: "vocab-teori", furi: "すいあつしけん", jp: "水圧試験", romaji: "suiatsu shiken", id_text: "Uji tekanan hidraulik / hydraulic pressure test", desc: "例: 配管工事完了後、接続部の漏れを確認するために水圧試験を実施する。→ Setelah pipa selesai dipasang, uji tekanan air dilakukan untuk memastikan tidak ada kebocoran. 試験圧力は仕様書の規定値で行う.", _origIndex: 1344 },
  { id: 1374, category: "haikan", source: "vocab-teori", furi: "さどる", jp: "サドル", romaji: "sadoru", id_text: "Saddle / braket penopang pipa di dinding/plafon", desc: "例: サドルは配管を壁・天井・床に固定するための支持金具だ。→ Braket pelana untuk menempelkan pipa ke dinding, plafon, atau lantai. サドル間隔が広すぎると配管がたわむ（lendut）.", _origIndex: 1346 },
  { id: 1375, category: "haikan", source: "vocab-teori", furi: "つぎて", jp: "継手", romaji: "tsugite", id_text: "Fitting / komponen sambungan antar pipa", desc: "例: 継手には、エルボ（曲がり）・チーズ（T字）・ソケット（直線）などがある。→ Berbagai jenis fitting: elbow (belok), tee (T), socket (lurus). 材料・用途・接合方法によって選定が変わる.", _origIndex: 1347 },
  { id: 1376, category: "haikan", source: "vocab-teori", furi: "ふらんじ", jp: "フランジ", romaji: "furanji", id_text: "Flensa / sambungan pipa dengan baut (mudah dibuka)", desc: "例: バルブや機器との接続にはフランジ接合が使われ、メンテナンスが容易だ。→ Sambungan flensa menggunakan baut sehingga mudah dibuka untuk perawatan. 溶接・ねじに比べて着脱が簡単.", _origIndex: 1348 },
  { id: 1377, category: "haikan", source: "vocab-teori", furi: "ばるぶ", jp: "バルブ", romaji: "barubu", id_text: "Katup / valve (mengatur aliran dalam pipa)", desc: "例: バルブは流体の開閉・流量調節に使う。ゲート・ボール・グローブ・逆止めなど種類が多い。→ Mengatur buka/tutup aliran. Jenis: gate valve (全開/全閉), ball valve (cepat), globe (kontrol aliran), check valve (searah).", _origIndex: 1349 },
  { id: 1378, category: "denki", source: "vocab-teori", furi: "はいせん", jp: "配線", romaji: "haisen", id_text: "Pengkabelan / wiring (instalasi kabel listrik)", desc: "例: 配線工事では、電線の太さ・種類・配線ルートを図面通りに施工する。→ Instalasi kabel listrik sesuai gambar: ukuran kabel, jenis, dan rute harus tepat. 誤配線 → 漏電・感電・火災のリスク.", _origIndex: 1350 },
  { id: 1379, category: "denki", source: "vocab-teori", furi: "ぶんき", jp: "分岐", romaji: "bunki", id_text: "Percabangan / branch (listrik atau pipa)", desc: "例: 幹線から各フロアへの分岐は、分電盤を介して行われる。→ Dari feeder utama, percabangan ke tiap lantai melalui panel distribusi. 電気でも配管でも: 幹線から分岐して各末端へ.", _origIndex: 1351 },
  { id: 1380, category: "denki", source: "vocab-teori", furi: "でんねつせん", jp: "電熱線", romaji: "dennetsusen", id_text: "Kabel pemanas elektrik anti-beku pipa luar", desc: "例: 寒冷地の屋外配管には、凍結防止のために電熱線を巻き付けて保温する。→ Di daerah dingin, kawat pemanas dililitkan pada pipa luar ruangan untuk mencegah pembekuan. 保温材と組み合わせて使用することが多い.", _origIndex: 1352 },
  { id: 1435, category: "setsubi_kougu", source: "vocab-jac", furi: "しつがいき", jp: "室外機", romaji: "shitsugaiki", id_text: "Unit luar AC / outdoor unit (kompresor+kondenser)", desc: "例: 室外機は建物の外に設置し、冷媒を圧縮して熱を外に放出する。室外機と室内機は冷媒管で接続する。→ Unit luar berisi kompresor dan kondenser. 設置場所は通気性確保が必須 — 囲ったり日光が強すぎると効率低下。", _origIndex: 1406 },
  { id: 1436, category: "haikan", source: "vocab-jac", furi: "しつないき", jp: "室内機", romaji: "shitsunaiki", id_text: "Unit dalam AC / indoor unit (evaporator & fan)", desc: "例: 室内機は壁や天井に取り付け、蒸発器で冷媒が蒸発するときの吸熱作用で室内を冷やす。→ Unit dalam dipasang di dinding/plafon, mendinginkan ruangan melalui evaporasi refrigeran. ドレン配管で結露水を外部に排水する。", _origIndex: 1407 },
  { id: 1437, category: "haikan", source: "vocab-jac", furi: "ふれあかこう", jp: "フレア加工", romaji: "furea kakou", id_text: "Flare processing — kembangkan ujung pipa tembaga", desc: "例: 冷媒管の接続はフレア加工で行い、フレアツールで銅管の端を拡張してからフレアナットで締め付ける。→ Ujung pipa tembaga dikembangkan dengan flare tool sebelum disambung. フレア不完全 → 冷媒漏れの原因。正確な加工が品質を左右する重要工程。", _origIndex: 1408 },
  { id: 1438, category: "haikan", source: "vocab-jac", furi: "どれんはいかん", jp: "ドレン配管", romaji: "doren haikan", id_text: "Pipa drain AC — alirkan air kondensasi unit dalam", desc: "例: 室内機で発生した結露水（ドレン水）はドレン配管を通じて屋外または排水管へ排水する。→ Air kondensasi dari unit dalam dialirkan ke luar lewat pipa drain. 勾配不足 → 水が逆流・水漏れ。ドレン配管は必ず下り勾配（1/100以上）で施工。", _origIndex: 1409 }
];
